<!DOCTYPE html>
<html>
<head>
<title>Simple Desktop Environment</title>
<style>
body {
  background-color: #282c34;
  font-family: sans-serif;
  margin: 0;
}

#desktop {
  width: 100%;
  height: 100vh;
  display: grid;
  grid-template-rows: auto 1fr auto; /* Taskbar at the bottom */
}

#taskbar {
  background-color: #3e4451;
  color: white;
  padding: 10px;
  text-align: left;
  display: flex;
  justify-content: space-between;
}

.taskbar-button {
  background-color: transparent;
  border: none;
  color: white;
  cursor: pointer;
  padding: 5px 10px;
  font-size: 16px;
}

#files-window, #notepad-window {
  width: 360px;
  height: 240px;
  border: 1px solid #3e4451;
  box-shadow: 0 2px 5px rgba(0, 0, 0, 0.3);
  display: flex;
  flex-direction: column;
}

.win-close {
  background-color: #dc3545;
  color: white;
  border: none;
  padding: 5px 10px;
  cursor: pointer;
  font-weight: bold;
}

#files-path {
  margin: 5px;
  color: #98aab5;
  font-size: 14px;
}

.fs-item {
  padding: 5px;
  cursor: pointer;
}

.fs-item:hover {
  background-color: #4c566a;
}

#tabs {
  background-color: #3e4451;
  display: flex;
}

.tab {
  padding: 8px 12px;
  cursor: pointer;
  border: none;
  background-color: transparent;
  font-size: 14px;
  color: #98aab5;
}

.tab:hover {
  background-color: #4c566a;
}

#editor {
  height: 180px;
  width: 100%;
  padding: 10px;
  font-family: monospace;
  resize: vertical;
}
</style>
</head>
<body>

<div id="desktop">
  <div id="taskbar">
    <button class="taskbar-button" id="open-files">Files</button>
    <button class="taskbar-button" id="open-notepad">Notepad</button>
  </div>
  <div id="file-listing">
    <!-- File listing will be populated by JavaScript -->
  </div>
  <div id="files-up"></div>
</div>

<div id="files-window" style="display: none;">
  <div id="files-path">/</div>
  <div id="file-listing">
    <div class="fs-item">bin</div>
    <div class="fs-item">etc</div>
    <div class="fs-item">home</div>
    <div class="fs-item">usr</div>
    <div class="fs-item">var</div>
    <div class="fs-item">home/user/Documents</div>
    <div class="fs-item">home/user/Downloads</div>
    <div class="fs-item">home/user/Pictures</div>
  </div>
  <div id="files-up">^</div>
</div>

<div id="notepad-window" style="display: none;">
  <div id="tabs">
    <button class="tab" id="new-tab">New</button>
  </div>
  <div id="editor" contenteditable="true"></div>
</div>

<script>
const desktop = document.getElementById('desktop');
const taskbarButtons = document.querySelectorAll('#taskbar button');
const filesWindow = document.getElementById('files-window');
const notepadWindow = document.getElementById('notepad-window');
const filesPathDisplay = document.getElementById('files-path');
const fileListing = document.getElementById('file-listing');
const filesUpButton = document.getElementById('files-up');

let currentFilesPath = '/';
let tabs = [];
let activeTabIndex = 0;

function populateFileListing() {
  fileListing.innerHTML = '';
  const fsItems = [
    'bin', 'etc', 'home', 'usr', 'var',
    'home/user/Documents', 'home/user/Downloads', 'home/user/Pictures'
  ];

  fsItems.forEach(item => {
    const itemElement = document.createElement('div');
    itemElement.classList.add('fs-item');
    itemElement.textContent = item;
    fileListing.appendChild(itemElement);
  });
}

function updateFilesPath() {
  filesPathDisplay.textContent = currentFilesPath;
}

function navigateUp() {
  const parts = currentFilesPath.split('/');
  if (parts.length > 1) {
    currentFilesPath = parts.slice(0, -1).join('/');
  } else {
    currentFilesPath = '/';
  }
  updateFilesPath();
  populateFileListing();
  filesUpButton.textContent = '^';
}

function openFiles() {
  filesWindow.style.display = 'flex';
  notepadWindow.style.display = 'none';
  currentFilesPath = '/';
  updateFilesPath();
  populateFileListing();
  filesUpButton.textContent = '^';
}

function openNotepad() {
  notepadWindow.style.display = 'flex';
  filesWindow.style.display = 'none';
  // Initialize tabs if they don't exist
  if (tabs.length === 0) {
    tabs.push({ name: "Untitled", content: "" });
  }
  updateTabs();
}

function createNewTab() {
  tabs.push({ name: "Untitled", content: "" });
  updateTabs();
}

function switchTab(index) {
  if (index >= 0 && index < tabs.length) {
    activeTabIndex = index;
    document.getElementById('editor').innerText = tabs[index].content;
  }
}

function saveTab() {
  tabs[activeTabIndex].content = document.getElementById('editor').innerText;
}

function updateTabs() {
  const tabContainer = document.querySelector('#tabs');
  tabContainer.innerHTML = '';

  tabs.forEach((tab, index) => {
    const tabButton = document.createElement('button');
    tabButton.classList.add('tab');
    tabButton.textContent = tab.name;
    tabButton.addEventListener('click', () => switchTab(index));
    tabContainer.appendChild(tabButton);
  });
}

// Load tabs from localStorage on page load
window.onload = function() {
  const savedTabs = JSON.parse(localStorage.getItem('notepad_tabs') || '[]');
  savedTabs.forEach((tabData, index) => {
    tabs.push({ name: "Untitled", content: tabData.content });
  });
  updateTabs();
};

// Save tabs to localStorage on window unload
window.onbeforeunload = function() {
  localStorage.setItem('notepad_tabs', JSON.stringify(tabs));
};


taskbarButtons.forEach(button => {
  button.addEventListener('click', () => {
    if (button.id === 'open-files') {
      openFiles();
    } else if (button.id === 'open-notepad') {
      openNotepad();
    }
  });
});

fileListing.addEventListener('click', (event) => {
  if (event.target.classList.contains('fs-item')) {
    const filePath = event.target.textContent;
    currentFilesPath += '/' + filePath;
    updateFilesPath();
    filesUpButton.textContent = '^';
  }
});

fileListing.addEventListener('DoubleClick', (event) => {
  if(currentFilesPath === '/') {
      return;
  }
  const filePath = event.target.textContent;
  currentFilesPath += '/' + filePath;
  updateFilesPath();
  filesUpButton.textContent = '^';
});

filesUpButton.addEventListener('click', navigateUp);

// Add a simple save functionality for the notepad
document.getElementById('editor').addEventListener('input', saveTab);
document.getElementById('editor').addEventListener('blur', saveTab); // Save on blur as well
</script>

</body>
</html>
